import{_ as e,o,c as t,ai as n}from"./chunks/framework.DyvBZb4W.js";const m=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"mods/sts2-map-enhance/faq.md","filePath":"mods/sts2-map-enhance/faq.md","lastUpdated":1779646093000}'),d={name:"mods/sts2-map-enhance/faq.md"};function s(r,a,c,i,h,l){return o(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="map-enhance-mod-是做什么的" tabindex="-1">Map Enhance Mod 是做什么的？ <a class="header-anchor" href="#map-enhance-mod-是做什么的" aria-label="Permalink to &quot;Map Enhance Mod 是做什么的？&quot;">​</a></h2><p>它用于增强 杀戮尖塔2 的地图阅读体验：按房间类型给节点上色，提供路线分析面板，并允许玩家在游戏内调整颜色、透明度和亮度。</p><h2 id="它会改变游戏机制吗" tabindex="-1">它会改变游戏机制吗？ <a class="header-anchor" href="#它会改变游戏机制吗" aria-label="Permalink to &quot;它会改变游戏机制吗？&quot;">​</a></h2><p>不会。它主要改变地图信息的呈现方式，不新增奖励、不修改路线生成，也不替玩家自动选择路线。</p><h2 id="路线分析是不是最优路线推荐" tabindex="-1">路线分析是不是最优路线推荐？ <a class="header-anchor" href="#路线分析是不是最优路线推荐" aria-label="Permalink to &quot;路线分析是不是最优路线推荐？&quot;">​</a></h2><p>不是。路线分析是轻量级规划辅助，会根据当前血量、金币、商店、精英和休息点等因素给出启发式评分。它适合用于快速比较路线，但不是完整的胜率模拟器。</p><h2 id="为什么-boss-或-ancient-节点没有染色" tabindex="-1">为什么 Boss 或 Ancient 节点没有染色？ <a class="header-anchor" href="#为什么-boss-或-ancient-节点没有染色" aria-label="Permalink to &quot;为什么 Boss 或 Ancient 节点没有染色？&quot;">​</a></h2><p>这些节点目前保持原版行为，主要是为了避免和游戏原有的悬停、动画或特殊节点表现冲突。</p><h2 id="在哪里改颜色" tabindex="-1">在哪里改颜色？ <a class="header-anchor" href="#在哪里改颜色" aria-label="Permalink to &quot;在哪里改颜色？&quot;">​</a></h2><p>进入：</p><p><code>Settings -&gt; 地图配置 / Map Config</code></p><p>可以修改每种房间类型的颜色、透明度、亮度，并实时预览。</p><h2 id="有快速开关吗" tabindex="-1">有快速开关吗？ <a class="header-anchor" href="#有快速开关吗" aria-label="Permalink to &quot;有快速开关吗？&quot;">​</a></h2><p>有。地图打开时可以按 <code>F8</code> 快速开启或关闭地图染色。</p><h2 id="配置文件为什么是-json-txt" tabindex="-1">配置文件为什么是 <code>.json.txt</code>？ <a class="header-anchor" href="#配置文件为什么是-json-txt" aria-label="Permalink to &quot;配置文件为什么是 `.json.txt`？&quot;">​</a></h2><p>杀戮尖塔2 的 Mod 文件夹可能会把 <code>*.json</code> 文件当作 Mod manifest 读取。为了避免配置文件被误识别，地图颜色配置使用 <code>map_color_config.json.txt</code>。</p><h2 id="安装时需要哪些文件" tabindex="-1">安装时需要哪些文件？ <a class="header-anchor" href="#安装时需要哪些文件" aria-label="Permalink to &quot;安装时需要哪些文件？&quot;">​</a></h2><p>发布包至少需要包含 <code>sts2_map_mod.dll</code> 和 <code>sts2_map_mod.pck</code>。同时应保留 <code>sts2_map_mod.json</code> 和 <code>map_color_config.json.txt</code>。</p><h2 id="这个-mod-可以商用或二次分发吗" tabindex="-1">这个 Mod 可以商用或二次分发吗？ <a class="header-anchor" href="#这个-mod-可以商用或二次分发吗" aria-label="Permalink to &quot;这个 Mod 可以商用或二次分发吗？&quot;">​</a></h2><p>本项目仅允许非商业使用。个人使用、修改和分享可以；商业使用或未经许可的付费打包不允许。</p><p>未经书面许可，不允许将本 Mod 重新上传到其他网站、镜像站、下载站、网盘合集、付费整合包或任何第三方分发渠道；也不允许分发修改后的版本。请始终从官方网站、Nexus Mods 或作者明确提供的下载入口获取文件。</p>',22)])])}const _=e(d,[["render",s]]);export{m as __pageData,_ as default};
